// 经典结构体 — 游戏中最常用
struct Vec2 {
    x: i32,
    y: i32,
}

// 元组结构体 — 适合包装新类型（newtype pattern）
struct TileIndex(usize);
struct PixelCoord(f64, f64);

// 单元结构体 — 用作标记类型
struct Player;
struct Enemy;

// C 风格枚举（Miu2D 使用这种）
enum PathType {
    PathOneStep = 0,
    SimpleMaxNpcTry = 1,
    PerfectMaxNpcTry = 2,
    PerfectMaxPlayerTry = 3,
    PathStraightLine = 4,
}

// Rust 独有的带数据枚举
enum GameState {
    Loading { progress: f32 },
    Playing { score: u32, level: u32 },
    Paused,
    GameOver { reason: String },
}

// 定义 trait
trait Renderable {
    fn render(&self);
    fn bounding_box(&self) -> Rect;

    // 默认实现
    fn is_visible(&self) -> bool {
        true
    }
}

// 为类型实现 trait
impl Renderable for Sprite {
    fn render(&self) { /* ... */ }
    fn bounding_box(&self) -> Rect { /* ... */ }
}

// 泛型函数
fn max_value<T: PartialOrd>(a: T, b: T) -> T {
    if a > b { a } else { b }
}

// 单态化后等价于：
fn max_value_i32(a: i32, b: i32) -> i32 { ... }
fn max_value_f64(a: f64, b: f64) -> f64 { ... }

// T 必须实现 PartialOrd（可比较）
fn find_min<T: PartialOrd>(slice: &[T]) -> &T {
    let mut min = &slice[0];
    for item in &slice[1..] {
        if item < min { min = item; }
    }
    min
}

// 多个 trait bound 使用 + 语法
fn process<T: Clone + Debug + Send>(data: &T) {
    println!("{:?}", data);
    let _copy = data.clone();
}

// trait bound 写法
fn complex<T: Clone + Debug + PartialEq + Send + Sync>(x: T) { ... }

// where 子句写法（更清晰）
fn complex<T>(x: T)
where
    T: Clone + Debug + PartialEq + Send + Sync,
{
    // ...
}

enum Option<T> {
    Some(T),  // 有值
    None,     // 无值
}

// 使用示例
fn find_entity(id: u32) -> Option<Entity> {
    if id == 0 {
        None  // 显式表示未找到
    } else {
        Some(Entity { id, x: 100.0, y: 200.0 })
    }
}

enum Result<T, E> {
    Ok(T),   // 成功
    Err(E),  // 失败
}

// Miu2D lib.rs 中的 zstd 解压使用 Result
#[wasm_bindgen]
pub fn zstd_decompress(data: &[u8]) -> Result<Vec<u8>, JsError> {
    let mut decoder = StreamingDecoder::new(data)
        .map_err(|e| JsError::new(&format!("zstd init error: {e}")))?;
    // ... ? 操作符自动传播错误
}

// 等价于：
let decoder = match StreamingDecoder::new(data) {
    Ok(d) => d,
    Err(e) => return Err(JsError::new(&format!("zstd init error: {e}"))),
};

// 使用 ? 操作符更简洁
let mut decoder = StreamingDecoder::new(data)
    .map_err(|e| JsError::new(&format!("zstd init error: {e}")))?;

