//! A* 寻路算法 - 高性能 Rust 实现
//!
//! C# Reference: JxqyHD/Engine/PathFinder.cs
//!
//! 支持的寻路类型：
//! - PathOneStep: 简单贪心，约 10 步
//! - SimpleMaxNpcTry: 贪心最佳优先搜索，maxTry=100
//! - PerfectMaxNpcTry: A* 算法用于 NPC，maxTry=100
//! - PerfectMaxPlayerTry: A* 算法用于玩家，maxTry=4000（C++ 为 16384）
//! - PathStraightLine: 直线，忽略障碍物（用于飞行者）

use hashbrown::{HashMap, HashSet};
use std::cmp::Ordering;
use std::collections::BinaryHeap;
use wasm_bindgen::prelude::*;

/// 寻路类型枚举
#[wasm_bindgen]
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum PathType {
    PathOneStep = 0,
    SimpleMaxNpcTry = 1,
    PerfectMaxNpcTry = 2,
    PerfectMaxPlayerTry = 3,
    PathStraightLine = 4,
}

/// 2D 向量/位置
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
struct Vec2 {
    x: i32,
    y: i32,
}

impl Vec2 {
    fn new(x: i32, y: i32) -> Self {
        Self { x, y }
    }

    /// 转换为像素坐标（用于距离计算）
    fn to_pixel(&self) -> (f64, f64) {
        let col = self.x;
        let row = self.y;
        let px = ((row & 1) * 32 + 64 * col) as f64;
        let py = (16 * row) as f64;
        (px, py)
    }

    /// 计算到另一点的像素距离
    fn pixel_distance(&self, other: &Vec2) -> f64 {
        let (px1, py1) = self.to_pixel();
        let (px2, py2) = other.to_pixel();
        let dx = px2 - px1;
        let dy = py2 - py1;
        (dx * dx + dy * dy).sqrt()
    }
}

/// A* 节点
#[derive(Clone, Copy)]
struct PathNode {
    tile: Vec2,
    f_cost: f64,
    g_cost: f64,
}

impl PartialEq for PathNode {
    fn eq(&self, other: &Self) -> bool {
        self.tile == other.tile
    }
}

impl Eq for PathNode {}

impl PartialOrd for PathNode {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for PathNode {
    fn cmp(&self, other: &Self) -> Ordering {
        other.f_cost.partial_cmp(&self.f_cost).unwrap_or(Ordering::Equal)
    }
}

/// 寻路器状态（可复用以减少内存分配）
#[wasm_bindgen]
pub struct PathFinder {
    map_width: i32,
    map_height: i32,
    obstacle_bitmap: Vec<u8>,
    hard_obstacle_bitmap: Vec<u8>,
    dynamic_bitmap: Vec<u8>,
}
